import{_ as t,o,c as a,ae as i}from"./chunks/framework.BdQd5MxT.js";const u=JSON.parse('{"title":"Weekly Robotics #356 — Digest for Xiaomi Robotics EI Team","description":"","frontmatter":{"title":"Weekly Robotics #356 — Digest for Xiaomi Robotics EI Team","date":"2026-04-17T00:00:00.000Z","issue":356,"tags":["robotics","embodied-ai","vln","ros2","drone","sensor-fusion"]},"headers":[],"relativePath":"bestpractice/weekly-robotics/weekly-robotics-356-2026-04-17.md","filePath":"bestpractice/weekly-robotics/weekly-robotics-356-2026-04-17.md"}'),r={name:"bestpractice/weekly-robotics/weekly-robotics-356-2026-04-17.md"};function n(s,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="weekly-robotics-356" tabindex="-1">Weekly Robotics #356 <a class="header-anchor" href="#weekly-robotics-356" aria-label="Permalink to &quot;Weekly Robotics #356&quot;">​</a></h1><p><em>April 13, 2026 | Curated for Xiaomi Robotics Embodied Intelligence Team</em></p><hr><h2 id="🔑-top-picks-this-week" tabindex="-1">🔑 Top Picks This Week <a class="header-anchor" href="#🔑-top-picks-this-week" aria-label="Permalink to &quot;🔑 Top Picks This Week&quot;">​</a></h2><h3 id="hunt-—-gps-denied-drone-navigation-9-10" tabindex="-1"><strong>HUNT</strong> — GPS-Denied Drone Navigation (9/10) <a class="header-anchor" href="#hunt-—-gps-denied-drone-navigation-9-10" aria-label="Permalink to &quot;**HUNT** — GPS-Denied Drone Navigation (9/10)&quot;">​</a></h3><p>A drone autonomy framework for GPS-denied, unstructured environments that replaces persistent global localization with <strong>instantaneous relative frames</strong> rebuilt from directly observable onboard signals (inertial attitude, barometric altitude, visual motion cues, target geometry).</p><p><strong>Relevance to Xiaomi:</strong> Directly applicable to indoor VLN scenarios where GPS is unavailable. The relative frame reconstruction approach aligns with our embodied AI research on navigation without absolute positioning.</p><hr><h3 id="fusioncore-—-ros-2-sensor-fusion-sdk-10-10" tabindex="-1"><strong>FusionCore</strong> — ROS 2 Sensor Fusion SDK (10/10) <a class="header-anchor" href="#fusioncore-—-ros-2-sensor-fusion-sdk-10-10" aria-label="Permalink to &quot;**FusionCore** — ROS 2 Sensor Fusion SDK (10/10)&quot;">​</a></h3><p>Open-source ROS 2 UKF-based sensor-fusion SDK with native support for 3D, GNSS, IMUs, wheel encoders, and more. Production-ready implementation.</p><p><strong>Relevance to Xiaomi:</strong> Immediate applicability for CyberOne and other robotics projects. The UKF-based approach with multi-sensor support matches our ROS 2 architecture needs for state estimation.</p><hr><h3 id="mighty-—-hermite-spline-trajectory-planning-8-10" tabindex="-1"><strong>MIGHTY</strong> — Hermite Spline Trajectory Planning (8/10) <a class="header-anchor" href="#mighty-—-hermite-spline-trajectory-planning-8-10" aria-label="Permalink to &quot;**MIGHTY** — Hermite Spline Trajectory Planning (8/10)&quot;">​</a></h3><p>Hermite spline-based planner performing spatiotemporal optimization while fully leveraging the continuous search space of a spline. Enables highly agile multirotor flight with reduced travel time and computation vs. state-of-the-art.</p><p><strong>Relevance to Xiaomi:</strong> Transferable to manipulator and mobile robot trajectory planning. The spline-based continuous optimization approach could enhance our motion planning stack.</p><hr><h3 id="nasa-artemis-ii-fault-tolerant-computer-7-10" tabindex="-1"><strong>NASA Artemis II Fault-Tolerant Computer</strong> (7/10) <a class="header-anchor" href="#nasa-artemis-ii-fault-tolerant-computer-7-10" aria-label="Permalink to &quot;**NASA Artemis II Fault-Tolerant Computer** (7/10)&quot;">​</a></h3><p>Design write-up of a fault-tolerant computer using &quot;fail silent&quot; architecture — if any redundant system has an issue, it remains silent, and the system always takes the available output.</p><p><strong>Relevance to Xiaomi:</strong> Interesting reference for safety-critical systems design, especially for humanoid robots operating near humans.</p><hr><h2 id="📅-notable-events" tabindex="-1">📅 Notable Events <a class="header-anchor" href="#📅-notable-events" aria-label="Permalink to &quot;📅 Notable Events&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Event</th><th>Date</th><th>Location</th><th>Relevance</th></tr></thead><tbody><tr><td><strong>Hands-on Workshop: Scaling VLA Models with Ray</strong></td><td>Apr 30</td><td>Pittsburgh</td><td>High — VLA scaling directly relevant to our embodied AI work</td></tr><tr><td><strong>Robotics Summit &amp; Expo 2026</strong></td><td>May 27-28</td><td>Boston</td><td>High — major industry event</td></tr><tr><td><strong>ICRA 2026</strong></td><td>Jun 1-5</td><td>Vienna</td><td>Very High — flagship robotics conference</td></tr></tbody></table><hr><h2 id="💡-quick-take" tabindex="-1">💡 Quick Take <a class="header-anchor" href="#💡-quick-take" aria-label="Permalink to &quot;💡 Quick Take&quot;">​</a></h2><p>This issue highlights the continued convergence of <strong>perception, planning, and control</strong> in embodied systems. HUNT&#39;s GPS-denied approach and FusionCore&#39;s sensor fusion capabilities are particularly relevant as we build more autonomous robots for unstructured environments.</p><p>The emphasis on <strong>safety-critical design</strong> (Artemis II) and <strong>efficient trajectory optimization</strong> (MIGHTY) reflects industry priorities that align with Xiaomi&#39;s robotics roadmap.</p><hr><p><em>Generated by GSD | <a href="/LIP/bestpractice/weekly-robotics/">View all Weekly Robotics digests</a></em></p>',28)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
